__global__ void fused_matmul(float* A, float* B, float* C, int M, int N, int K) {
    int tid = threadIdx.y * 16 + threadIdx.x;
    int block_row = blockIdx.y * 128;
    int block_col = blockIdx.x * 128;
    int thread_row = threadIdx.y * 8;
    int thread_col = threadIdx.x * 8;
    __shared__ float As[4224];
    __shared__ float Bs[4128];
    float acc[64];
    for (int i = 0; i < 64; i++) {
        acc[i] = 0.0f;
    }
    float regA[8];
    float regB[8];
    for (int tile_k = 0; tile_k < K; tile_k += 32) {
        for (int li = tid; li < 4096; li += 256) {
            int a_r = li / 32;
            int a_c = li % 32;
            As[a_r * 33 + a_c] = ((block_row + a_r < M && tile_k + a_c < K) ? (A[(block_row + a_r) * K + (tile_k + a_c)]) : (0.0f));
        }
        for (int lj = tid; lj < 4096; lj += 256) {
            int b_r = lj / 128;
            int b_c = lj % 128;
            Bs[b_r * 129 + b_c] = ((tile_k + b_r < K && block_col + b_c < N) ? (B[(tile_k + b_r) * N + (block_col + b_c)]) : (0.0f));
        }
        __syncthreads();
        #pragma unroll
        for (int kk = 0; kk < 32; kk++) {
            #pragma unroll
            for (int m = 0; m < 8; m++) {
                regA[m] = As[(thread_row + m) * 33 + kk];
            }
            #pragma unroll
            for (int n = 0; n < 8; n++) {
                regB[n] = Bs[kk * 129 + (thread_col + n)];
            }
            #pragma unroll
            #pragma unroll
            for (int m = 0; m < 8; m++) {
                #pragma unroll
                for (int n = 0; n < 8; n++) {
                    acc[m * 8 + n] = acc[m * 8 + n] + regA[m] * regB[n];
                }
            }
        }
        __syncthreads();
    }
    for (int wm = 0; wm < 8; wm++) {
        for (int wn = 0; wn < 8; wn++) {
            if (block_row + thread_row + wm < M && block_col + thread_col + wn < N) {
                C[(block_row + thread_row + wm) * N + (block_col + thread_col + wn)] = acc[wm * 8 + wn];
            }
        }
    }
}
